import React from 'react';
import { motion } from 'framer-motion';
import FooterBackground from '../assets/footer.png'; // ¡IMPORTA LA IMAGEN AQUÍ!

// --- Iconos SVG (simulando los de la imagen, puedes usar librerías de iconos reales como FontAwesome/React-icons) ---
const LocationIcon = ({ size = '20px', color = '#999' }) => (
  <svg viewBox="0 0 24 24" width={size} height={size} fill={color} style={{ verticalAlign: 'middle', marginRight: '8px' }}>
    <path d="M12 2C8.13 2 5 5.13 5 9c0 5.25 7 13 7 13s7-7.75 7-13c0-3.87-3.13-7-7-7zm0 9.5c-1.38 0-2.5-1.12-2.5-2.5s1.12-2.5 2.5-2.5 2.5 1.12 2.5 2.5-1.12 2.5-2.5 2.5z"/>
  </svg>
);

const PhoneIcon = ({ size = '20px', color = '#999' }) => (
  <svg viewBox="0 0 24 24" width={size} height={size} fill={color} style={{ verticalAlign: 'middle', marginRight: '8px' }}>
    <path d="M6.62 10.79c1.44 2.83 3.76 5.14 6.59 6.59l2.2-2.2c.27-.27.67-.36 1.02-.24 1.12.37 2.33.57 3.57.57.55 0 1 .45 1 1V20c0 .55-.45 1-1 1-9.39 0-17-7.61-17-17 0-.55.45-1 1-1h3.5c.55 0 1 .45 1 1v3.5c0 .35-.09.7-.24 1.02l-2.2 2.2z"/>
  </svg>
);

const EmailIcon = ({ size = '20px', color = '#999' }) => (
  <svg viewBox="0 0 24 24" width={size} height={size} fill={color} style={{ verticalAlign: 'middle', marginRight: '8px' }}>
    <path d="M20 4H4c-1.1 0-1.99.9-1.99 2L2 18c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V6c0-1.1-.9-2-2-2zm0 4l-8 5-8-5V6l8 5 8-5v2z"/>
  </svg>
);

const ScheduleIcon = ({ size = '20px', color = '#999' }) => (
  <svg viewBox="0 0 24 24" width={size} height={size} fill={color} style={{ verticalAlign: 'middle', marginRight: '8px' }}>
    <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm.9 15.5h-1.8v-6l4.7 2.8-.9 1.5-3 1.8zm-1.9-8.5c-.55 0-1-.45-1-1s.45-1 1-1 1 .45 1 1-.45 1-1 1z"/>
  </svg>
);

// --- Componente para los iconos de redes sociales (círculos blancos) ---
const SocialIconCircle = ({ children, href }) => (
  <motion.a
    href={href}
    target="_blank"
    rel="noopener noreferrer"
    style={{
      width: '40px',
      height: '40px',
      borderRadius: '50%',
      backgroundColor: '#fff',
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      textDecoration: 'none',
      transition: 'background-color 0.3s ease',
    }}
    whileHover={{ scale: 1.1, backgroundColor: 'rgba(255,255,255,0.8)' }}
    whileTap={{ scale: 0.9 }}
  >
    {children}
  </motion.a>
);

const FacebookSVG = ({ size = '24px', color = '#2F4F8B' }) => (
  <svg viewBox="0 0 24 24" width={size} height={size} fill={color}><path d="M17 2H14C12.02 2 10 3.19 10 6v3H7v4h3v8h4v-8h3l1-4h-4V6c0-.55.45-1 1-1h3V2z"/></svg>
);


const FooterBar = () => {
  const styles = {
    footerContainer: {
      position: 'relative',
      backgroundColor: '#000', // Un color de fallback si la imagen no carga
      color: '#fff',
      padding: '60px 0 20px 0', // Más padding arriba, menos abajo
      fontFamily: "'Inter', sans-serif", // Una fuente limpia para la información
      fontSize: '15px',
      overflow: 'hidden', // Asegura que el contenido no se desborde si hay animaciones
    },
    backgroundImage: {
      position: 'absolute',
      top: 0,
      left: 0,
      width: '100%',
      height: '100%',
      backgroundImage: `url(${FooterBackground})`, // ¡USA LA VARIABLE IMPORTADA AQUÍ!
      backgroundSize: 'cover',
      backgroundPosition: 'center',
      filter: 'brightness(0.5) contrast(1.2)', // Ajusta brillo y contraste para que el texto sea legible
      zIndex: 1,
    },
    overlay: {
      position: 'absolute',
      top: 0,
      left: 0,
      width: '100%',
      height: '100%',
      backgroundColor: 'rgba(0, 0, 0, 0.6)', // Overlay oscuro para mejorar legibilidad
      zIndex: 2,
    },
    contentWrapper: {
      position: 'relative',
      zIndex: 3, // Asegura que el contenido esté por encima del fondo y el overlay
      maxWidth: '1200px',
      margin: '0 auto',
      padding: '0 40px', // Padding horizontal para el contenido
      display: 'flex',
      flexWrap: 'wrap',
      justifyContent: 'space-between',
      alignItems: 'flex-start',
      gap: '40px', // Espacio entre columnas
    },
    column: {
      flex: '1',
      minWidth: '250px', // Ancho mínimo para cada columna
      padding: '10px 0',
    },
    logoSection: {
      marginBottom: '20px',
    },
    logo: {
      width: '180px', // Tamaño del logo
      marginBottom: '15px',
      filter: 'brightness(2)', // Para hacer el logo blanco o más visible si es oscuro
    },
    slogan: {
      fontSize: '14px',
      color: '#aaa',
      margin: 0,
      letterSpacing: '0.5px',
    },
    contactInfo: {
      listStyle: 'none',
      padding: 0,
      margin: '0 0 30px 0',
    },
    contactItem: {
      display: 'flex',
      alignItems: 'center',
      marginBottom: '12px',
      color: '#ccc',
      fontSize: '15px',
      lineHeight: '1.4',
    },
    contactLink: {
      color: '#ccc',
      textDecoration: 'none',
      transition: 'color 0.3s ease',
      '&:hover': {
        color: '#fff',
      },
    },
    socialIcons: {
      display: 'flex',
      gap: '15px',
      marginTop: '20px',
    },
    legalLinks: {
      listStyle: 'none',
      padding: 0,
      margin: 0,
    },
    legalLinkItem: {
      marginBottom: '10px',
    },
    legalLink: {
      color: '#999',
      textDecoration: 'none',
      fontSize: '15px',
      transition: 'color 0.3s ease',
      '&:hover': {
        color: '#fff',
      },
    },
    heading: {
      fontSize: '18px',
      fontWeight: 'bold',
      color: '#eee',
      marginBottom: '25px',
      textTransform: 'uppercase',
      letterSpacing: '1px',
    },
    copyrightSection: {
      position: 'relative',
      zIndex: 3,
      borderTop: '1px solid rgba(255,255,255,0.1)',
      marginTop: '60px',
      paddingTop: '20px',
      textAlign: 'center',
      fontSize: '13px',
      color: '#999',
    },
  };

  return (
    <footer style={styles.footerContainer}>
      <div style={styles.backgroundImage}></div> {/* Imagen de fondo */}
      <div style={styles.overlay}></div> {/* Overlay para oscurecer la imagen */}

      <div style={styles.contentWrapper}>
        {/* Columna 1: Logo y contacto */}
        <div style={styles.column}>
          <div style={styles.logoSection}>
            {/* Si tu logo de Kabanyal es un archivo de imagen, impórtalo también y úsalo aquí */}
            <img src="/media/logo/kabanyal_logo_white.png" alt="Kabanyal Logo" style={styles.logo} /> {/* Ajusta la ruta de tu logo */}
            <p style={styles.slogan}>
              Compañía
            </p>
          </div>

          <ul style={styles.contactInfo}>
            <li style={styles.contactItem}>
              <LocationIcon />
              Plaza Armada Española, 1, 46011, Valencia
            </li>
            <li style={styles.contactItem}>
              <PhoneIcon />
              Móvil: 747 42 77 46
            </li>
            <li style={styles.contactItem}>
              <EmailIcon />
              <a href="mailto:info@kabanyal.es" style={styles.contactLink}>info@kabanyal.es</a>
            </li>
            <li style={styles.contactItem}>
              <ScheduleIcon />
              De martes a viernes de 12:00h. a 00:00h.
            </li>
             <li style={styles.contactItem}>
              <ScheduleIcon />
              Sábado y domingo de 10:00h. a 00:00h.
            </li>
          </ul>

          <div style={styles.socialIcons}>
            <SocialIconCircle href="https://facebook.com">
                <FacebookSVG color="#2F4F8B" />
            </SocialIconCircle>
            <SocialIconCircle href="https://instagram.com">
                {/* Ícono de Instagram (deberías tener tu propio SVG o usar una librería) */}
                <svg viewBox="0 0 24 24" width="24px" height="24px" fill="#2F4F8B"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm-2 15h4V9h-4v8zm-2-2h2v-2H8v2zm0-4h2V9H8v2zm8 0h2v-2h-2v2zm0-4h2V9h-2v2z"/></svg> {/* Placeholder */}
            </SocialIconCircle>
            {/* Añade más iconos de redes sociales aquí */}
          </div>
        </div>

        {/* Columna 2: Enlaces legales (puedes agregar más si necesitas) */}
        <div style={{ ...styles.column, flex: 'none', width: 'auto' }}>
          <h3 style={styles.heading}>Información</h3>
          <ul style={styles.legalLinks}>
            <li style={styles.legalLinkItem}>
              <a href="/aviso-legal" style={styles.legalLink}>Aviso Legal</a>
            </li>
            <li style={styles.legalLinkItem}>
              <a href="/politica-de-privacidad" style={styles.legalLink}>Política de privacidad</a>
            </li>
            <li style={styles.legalLinkItem}>
              <a href="/politica-de-cookies" style={styles.legalLink}>Política de cookies</a>
            </li>
          </ul>
        </div>
      </div>

      {/* Sección de Copyright */}
      <div style={styles.copyrightSection}>
        <p>
          Kabanyal es una marca registrada de Hostelería Kabanyal SL. Prohibida su uso sin autorización expresa.
        </p>
      </div>
    </footer>
  );
};

export default FooterBar;
